t.script:
window.addEventListener('pageshow', function (e) {
    if (!e.persisted) { return; }
    fetch('/web/session/get_session_info', {
        method: 'POST',
        headers: {'Content-Type': 'application/json'},
        body: JSON.stringify({jsonrpc: '2.0', method: 'call', id: 1, params: {}})
    }).then(function(r) { return r.json(); }).then(function(d) {
        if (!d.result || !d.result.uid) { window.location.replace('/web/login'); }
    }).catch(function() { window.location.replace('/web/login'); });
});

template.script:
(function () {
    function pad(n) { return n < 10 ? '0' + n : '' + n; }
    function fmt(d) { return d.getFullYear() + '-' + pad(d.getMonth()+1) + '-' + pad(d.getDate()); }
    var customRow = document.getElementById('fb-custom-row');
    var kustomBtn = document.getElementById('fb-kustom');
    var filterMode = document.getElementById('fb-filter-mode');
    function go(from, to) {
        filterMode.value = 'preset';
        document.getElementById('fb-date-from').value = from;
        document.getElementById('fb-date-to').value = to;
        document.getElementById('filterForm').submit();
    }
    function hilite(id) {
        ['fb-bulan-ini','fb-3-bulan','fb-tahun-ini','fb-kuartal','fb-kustom'].forEach(function(bid) {
            document.getElementById(bid).classList.remove('active');
        });
        document.getElementById(id).classList.add('active');
    }
    document.getElementById('fb-bulan-ini').addEventListener('click', function () {
        hilite('fb-bulan-ini'); customRow.classList.remove('visible');
        var n = new Date();
        go(fmt(new Date(n.getFullYear(), n.getMonth(), 1)), fmt(n));
    });
    document.getElementById('fb-3-bulan').addEventListener('click', function () {
        hilite('fb-3-bulan'); customRow.classList.remove('visible');
        var n = new Date(), a = new Date(n);
        a.setMonth(a.getMonth() - 3); go(fmt(a), fmt(n));
    });
    document.getElementById('fb-tahun-ini').addEventListener('click', function () {
        hilite('fb-tahun-ini'); customRow.classList.remove('visible');
        var n = new Date();
        go(fmt(new Date(n.getFullYear(), 0, 1)), fmt(n));
    });
    document.getElementById('fb-kuartal').addEventListener('click', function () {
        hilite('fb-kuartal'); customRow.classList.remove('visible');
        var n = new Date(), q = Math.floor(n.getMonth() / 3);
        go(fmt(new Date(n.getFullYear(), q * 3, 1)), fmt(n));
    });
    kustomBtn.addEventListener('click', function () {
        if (customRow.classList.contains('visible')) {
            customRow.classList.remove('visible');
            kustomBtn.classList.remove('active');
        } else {
            hilite('fb-kustom');
            customRow.classList.add('visible');
            filterMode.value = 'custom';
        }
    });
    var params = new URLSearchParams(window.location.search);
    if (params.get('filter_mode') === 'custom' && document.getElementById('fb-date-from').value) {
        hilite('fb-kustom');
        customRow.classList.add('visible');
    }
})();
